const { v4: uuidv4 } = require('uuid');

let stockItems = [];

function item(code, name, qty, category, subcategory, serials = []) {
  return {
    id: uuidv4(),
    product_code: code,
    name,
    category,
    subcategory,
    quantity: qty,
    serials,
    min_stock: 0,
    price: 0,
    location: '',
    notes: '',
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
}

